// TestCreateBookmark_InvalidURL_MessageDoesNotLeakSubmittedURL is
// Trailhead's own scar (H-12 / #2's redaction) applied one layer up: the
// handler must not re-introduce the submitted URL when composing its
// invalid_url message, even though the adapter's own error is redacted.
// from interview: Q7
func TestCreateBookmark_InvalidURL_MessageDoesNotLeakSubmittedURL(t *testing.T) {
	srv, _ := newTestServer(t)
	const submitted = "ftp://totally-distinctive-marker-string"

	resp, err := http.Post(srv.URL+"/api/bookmarks", "application/json",
		strings.NewReader(`{"url": "`+submitted+`"}`))
	require.NoError(t, err)
	require.Equal(t, http.StatusBadRequest, resp.StatusCode)

	var body errorEnvelope
	decodeJSON(t, resp, &body)
	assert.NotContains(t, body.Message, submitted, "invalid_url message must not echo the submitted URL")
	assert.NotContains(t, body.Message, "totally-distinctive-marker-string")
}

