// TestCreateBookmark_OversizedBody_Returns413PayloadTooLarge: cap is
// 16 KiB (16384 bytes), applied before decode, POST only.
// from interview: Q10
func TestCreateBookmark_OversizedBody_Returns413PayloadTooLarge(t *testing.T) {
	srv, _ := newTestServer(t)

	// A syntactically valid but oversized body: pad the title well past
	// 16 KiB so the cap trips regardless of exact framing overhead.
	oversizedTitle := strings.Repeat("a", 20000)
	body := `{"url": "https://example.com/a", "title": "` + oversizedTitle + `"}`

	resp, err := http.Post(srv.URL+"/api/bookmarks", "application/json", strings.NewReader(body))
	require.NoError(t, err)
	assert.Equal(t, http.StatusRequestEntityTooLarge, resp.StatusCode)

	var errBody errorEnvelope
	decodeJSON(t, resp, &errBody)
	assert.Equal(t, "payload_too_large", errBody.Error)
}

