// TestBoard_EmptyRepo_ReturnsThreeEmptyArraysNotNull checks the raw wire
// bytes, not just the decoded Go value — decoding null into a slice field
// can produce the same Go nil a decoded [] would in some paths, so
// asserting on decoded board.Inbox alone wouldn't reliably catch a
// null-instead-of-[] regression the way checking the raw JSON text does.
func TestBoard_EmptyRepo_ReturnsThreeEmptyArraysNotNull(t *testing.T) {
	srv, _ := newTestServer(t)
	resp, err := http.Get(srv.URL + "/api/board")
	require.NoError(t, err)
	require.Equal(t, http.StatusOK, resp.StatusCode)

	var buf bytes.Buffer
	_, err = buf.ReadFrom(resp.Body)
	require.NoError(t, err)
	defer resp.Body.Close()

	raw := buf.String()
	assert.Contains(t, raw, `"inbox":[]`)
	assert.Contains(t, raw, `"reading":[]`)
	assert.Contains(t, raw, `"done":[]`)
	assert.NotContains(t, raw, `"inbox":null`)
	assert.NotContains(t, raw, `"reading":null`)
	assert.NotContains(t, raw, `"done":null`)
}

